const body = $input.first().json || {};
const now = new Date();
const timestamp = now.toISOString();

const stableStringify = (value) => {
  if (Array.isArray(value)) return `[${value.map(stableStringify).join(',')}]`;
  if (value && typeof value === 'object') {
    return `{${Object.keys(value).sort().map((key) => `${JSON.stringify(key)}:${stableStringify(value[key])}`).join(',')}}`;
  }
  return JSON.stringify(value);
};

const hashText = (text) => {
  let hash = 2166136261;
  for (let i = 0; i < text.length; i += 1) {
    hash ^= text.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(16).padStart(8, '0');
};

const numberOr = (value, fallback = 0) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
};

const boolOr = (value, fallback = false) => {
  if (value === undefined || value === null || value === '') return fallback;
  return value === true || value === 'true' || value === 1 || value === '1';
};

if (!body || typeof body !== 'object' || (!body.thingId && !body.features)) {
  const correlationId = `CID-DITTO-INVALID-${now.getTime()}`;
  return [{
    json: {
      correlation_id: correlationId,
      event_id: `EVT-DITTO-INVALID-${now.getTime()}`,
      thing_id: $env.PRIMARY_THING_ID || 'building:floor1:elevator',
      agent_source: '01_ingestion_surveillance_agent',
      event_type: 'AUDIT_EVENT',
      severity: 'WARNING',
      timestamp,
      system_mode: 'DEGRADED',
      risk_score: 0,
      payload: {
        health: {
          component: 'ditto',
          status: 'DEGRADED',
          reason: 'INVALID_DITTO_RESPONSE'
        }
      },
      risk_analysis: {},
      triggered_action: {},
      metadata: {
        workflow: '01_ingestion_surveillance_agent',
        node: 'Canonicalize Twin Event',
        schema_version: '1.0',
        source: 'ditto_poll'
      },
      raw_thing: body,
      duplicate_hash: hashText(stableStringify(body)),
      duplicate: false,
      processing_status: 'INVALID_DITTO_RESPONSE'
    }
  }];
}

const features = body.features || {};
const attributes = body.attributes || {};
const cabinRaw = features.cabin?.properties || {};
const doorRaw = features.door?.properties || {};
const motorRaw = features.motor?.properties || {};
const securityRaw = features.security?.properties || {};
const thingId = body.thingId || attributes.thing_id || $env.PRIMARY_THING_ID || 'building:floor1:elevator';
const thingToken = thingId.replace(/[^a-zA-Z0-9]/g, '-');
const correlationId = body.correlation_id || attributes.correlation_id || `CID-${thingToken}-${now.getTime()}`;

const cabin = {
  current_floor: numberOr(cabinRaw.current_floor, 0),
  target_floor: numberOr(cabinRaw.target_floor ?? cabinRaw.current_floor, 0),
  direction: cabinRaw.direction || 'IDLE',
  load_kg: numberOr(cabinRaw.load_kg ?? cabinRaw.payload_weight_kg, 0),
  max_load_kg: numberOr(cabinRaw.max_load_kg, 800),
  speed_ms: numberOr(cabinRaw.speed_ms, 0),
  temperature_c: numberOr(cabinRaw.temperature_c, 22),
  emergency_stop: boolOr(cabinRaw.emergency_stop, false),
  between_floors: boolOr(cabinRaw.between_floors, false)
};

const door = {
  state: doorRaw.state || 'UNKNOWN',
  forced_entry: boolOr(doorRaw.forced_entry ?? doorRaw.door_forced_entry, false),
  cycle_count: numberOr(doorRaw.cycle_count, 0),
  force_sensor_n: numberOr(doorRaw.force_sensor_n, 0),
  blocked: boolOr(doorRaw.blocked, false)
};

const motor = {
  vibration_g: numberOr(motorRaw.vibration_g ?? motorRaw.vibration_level ?? motorRaw.vibration_ms2, 0),
  vibration_baseline_g: numberOr(motorRaw.vibration_baseline_g ?? motorRaw.vibration_baseline_ms2, 0.05),
  temperature_c: numberOr(motorRaw.temperature_c, 0),
  hours_operated: numberOr(motorRaw.hours_operated ?? motorRaw.run_hours, 0),
  current_draw_a: numberOr(motorRaw.current_draw_a, 0),
  power_kw: numberOr(motorRaw.power_kw, 0),
  health_status: motorRaw.health_status || 'UNKNOWN'
};

const security = {
  audio_distress: boolOr(securityRaw.audio_distress_active ?? securityRaw.audio_distress_detected, false),
  rfid_last_card: securityRaw.rfid_last_card || '',
  rfid_access_granted: boolOr(securityRaw.rfid_access_granted, true),
  unauthorized_access_attempts: numberOr(securityRaw.unauthorized_access_attempts, 0),
  alert_level: securityRaw.alert_level || 'NORMAL',
  state: securityRaw.state || 'NORMAL'
};

let eventType = 'TELEMETRY_UPDATE';
let severity = 'INFO';
if (door.forced_entry || security.audio_distress) {
  eventType = 'SECURITY_BREACH';
  severity = 'CRITICAL';
} else if (motor.vibration_g > motor.vibration_baseline_g * 2.5 || motor.temperature_c > 85 || cabin.emergency_stop) {
  eventType = 'ANOMALY_DETECTED';
  severity = 'WARNING';
}

const payload = { cabin, door, motor, security };
const duplicateHash = hashText(stableStringify({
  thing_id: thingId,
  system_mode: attributes.system_mode || 'NORMAL',
  payload
}));

return [{
  json: {
    correlation_id: correlationId,
    event_id: `EVT-${thingToken}-${now.getTime()}`,
    thing_id: thingId,
    agent_source: '01_ingestion_surveillance_agent',
    event_type: eventType,
    severity,
    timestamp,
    system_mode: attributes.system_mode || 'NORMAL',
    risk_score: 0,
    payload,
    risk_analysis: {},
    triggered_action: {},
    metadata: {
      workflow: '01_ingestion_surveillance_agent',
      node: 'Canonicalize Twin Event',
      schema_version: '1.0',
      source: 'ditto_poll'
    },
    timeline_entry: {
      ts: timestamp,
      floor: cabin.current_floor,
      direction: cabin.direction,
      load_kg: cabin.load_kg,
      door_state: door.state,
      motor_temp_c: motor.temperature_c,
      motor_vibration_g: motor.vibration_g,
      power_kw: motor.power_kw,
      forced_entry: door.forced_entry,
      audio_distress: security.audio_distress,
      emergency_stop: cabin.emergency_stop
    },
    raw_thing: body,
    duplicate_hash: duplicateHash,
    duplicate: false,
    processing_status: 'RECORDED'
  }
}];

const event = $input.first().json;
const state = $getWorkflowStaticData('global');
const thingId = event.thing_id || 'unknown';
const key = `ingestion:${thingId}`;
const now = Date.now();

state[key] = state[key] || {
  last_duplicate_hash: null,
  behavior_timeline: [],
  ditto_failures: []
};

const memory = state[key];
const isDuplicate = !!event.duplicate_hash && memory.last_duplicate_hash === event.duplicate_hash;
memory.last_duplicate_hash = event.duplicate_hash || memory.last_duplicate_hash;

if (event.timeline_entry) {
  memory.behavior_timeline.push(event.timeline_entry);
}

const cutoff = now - 60_000;
memory.behavior_timeline = memory.behavior_timeline
  .filter((entry) => Number.isFinite(new Date(entry.ts).getTime()) && new Date(entry.ts).getTime() >= cutoff)
  .slice(-120);

const cabin = event.payload?.cabin || {};
const door = event.payload?.door || {};
const motor = event.payload?.motor || {};
const security = event.payload?.security || {};
const riskSeed = (
  (door.forced_entry ? 45 : 0) +
  (security.audio_distress ? 40 : 0) +
  (cabin.emergency_stop ? 30 : 0) +
  (motor.temperature_c > 85 ? 20 : 0) +
  (motor.vibration_g > motor.vibration_baseline_g * 2.5 ? 20 : 0)
);

state[key] = memory;

return [{
  json: {
    ...event,
    duplicate: isDuplicate,
    processing_status: isDuplicate ? 'DUPLICATE' : event.processing_status || 'RECORDED',
    risk_score: Math.min(100, riskSeed),
    behavior_timeline: memory.behavior_timeline,
    metadata: {
      ...(event.metadata || {}),
      duplicate_window_seconds: 60,
      duplicate_detected: isDuplicate
    }
  }
}];

const event = $input.first().json;
const p = event.payload || {};
const c = p.cabin || {};
const d = p.door || {};
const m = p.motor || {};
const s = p.security || {};

const n = (value) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};

const b = (value) => value === true || value === 'true' || value === 1 || value === '1';

event._db_query = `
INSERT INTO telemetry_raw (
  time, thing_id, event_id, event_type, system_mode,
  current_floor, target_floor, load_kg, speed_ms, door_state,
  forced_entry, audio_distress, motor_temp_c, vibration_g,
  power_kw, current_draw_a, hours_operated, risk_score, raw_payload,
  correlation_id, duplicate_hash, source, schema_version,
  processing_status, duplicate, agent_source, severity, metadata
) VALUES (
  $1::timestamptz, $2, $3, $4, $5,
  $6::smallint, $7::smallint, $8::real, $9::real, $10,
  $11::boolean, $12::boolean, $13::real, $14::real,
  $15::real, $16::real, $17::real, $18::smallint, $19::jsonb,
  $20, $21, $22, $23,
  $24, $25::boolean, $26, $27, $28::jsonb
) ON CONFLICT (event_id) DO UPDATE SET
  processing_status = EXCLUDED.processing_status,
  duplicate = EXCLUDED.duplicate,
  metadata = telemetry_raw.metadata || EXCLUDED.metadata;
`;

event._db_params = [
  event.timestamp || new Date().toISOString(),
  event.thing_id,
  event.event_id,
  event.event_type,
  event.system_mode || 'NORMAL',
  n(c.current_floor),
  n(c.target_floor),
  n(c.load_kg),
  n(c.speed_ms),
  d.state || 'UNKNOWN',
  b(d.forced_entry),
  b(s.audio_distress),
  n(m.temperature_c),
  n(m.vibration_g),
  n(m.power_kw),
  n(m.current_draw_a),
  n(m.hours_operated),
  n(event.risk_score || event.risk_analysis?.risk_score || 0),
  JSON.stringify(event),
  event.correlation_id,
  event.duplicate_hash,
  event.metadata?.source || 'ditto_poll',
  event.metadata?.schema_version || '1.0',
  event.processing_status || 'RECORDED',
  b(event.duplicate),
  event.agent_source || '01_ingestion_surveillance_agent',
  event.severity || 'INFO',
  JSON.stringify(event.metadata || {})
];

return [{ json: event }];

const state = $getWorkflowStaticData('global');
const input = $input.first().json || {};
const now = new Date().toISOString();
const thingId = $env.PRIMARY_THING_ID || 'building:floor1:elevator';
const key = `ditto_failures:${thingId}`;
state[key] = (state[key] || 0) + 1;
return [{
  json: {
    agent: '01_ingestion_surveillance_agent',
    event_type: 'INGESTION_PIPELINE_FAILURE',
    status: 'FAILED',
    severity: 'WARNING',
    thing_id: thingId,
    correlation_id: `CID-INGESTION-FAIL-${Date.now()}`,
    error_message: (input && (input.message || input.error || JSON.stringify(input))) || 'unknown_error',
    consecutive_failures: state[key],
    timestamp: now,
    details: { failed_at: now, payload: input }
  }
}];
